class Solution {
public:
    string minimizeStringValue(string s) {
        string res = "";
        set<char> st;
        for (char c : s) {
            if (c == '?') {
                char ch = 'a';
                while (st.find(ch) != st.end()) {
                    ch++;
                }
                res += ch;
                st.insert(ch);
            } else {
                res += c;
                st.insert(c);
            }
        }
        return res;
    }
};
